import { useEffect, useState } from 'react';
import type { KaizenPhase, AIAnalysis } from '../types';
import { generateAgentSuggestion } from '../engine/agentSuggestions';
import ChatInterface from './ChatInterface';

interface AgentPanelProps {
    phase: KaizenPhase;
}

export default function AgentPanel({ phase }: AgentPanelProps) {
    const [analysis, setAnalysis] = useState<AIAnalysis | null>(null);
    const [isTyping, setIsTyping] = useState(false);

    useEffect(() => {
        // Simulate AI loading / thinking
        setIsTyping(true);
        setAnalysis(null);

        const timer = setTimeout(() => {
            setAnalysis(generateAgentSuggestion(phase));
            setIsTyping(false);
        }, 600); // 600ms fake delay

        return () => clearTimeout(timer);
    }, [phase.id]);

    const [activeTab, setActiveTab] = useState<'insights' | 'chat'>('insights');

    return (
        <div>
            <div style={{ display: 'flex', alignItems: 'center', marginBottom: '1rem' }}>
                <h3 style={{ margin: 0, display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <span>≡ƒñû</span> Copilot Agent
                </h3>
                <span className="ai-badge">Autonomous Mode</span>
            </div>

            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1.5rem', borderBottom: '1px solid var(--border-color)', paddingBottom: '0.5rem' }}>
                <button
                    onClick={() => setActiveTab('insights')}
                    style={{
                        background: 'transparent',
                        border: 'none',
                        color: activeTab === 'insights' ? 'var(--accent-primary)' : 'var(--text-muted)',
                        fontWeight: activeTab === 'insights' ? '600' : 'normal',
                        cursor: 'pointer',
                        padding: '0.25rem 0.5rem'
                    }}
                >
                    Phase Insights
                </button>
                <button
                    onClick={() => setActiveTab('chat')}
                    style={{
                        background: 'transparent',
                        border: 'none',
                        color: activeTab === 'chat' ? 'var(--accent-primary)' : 'var(--text-muted)',
                        fontWeight: activeTab === 'chat' ? '600' : 'normal',
                        cursor: 'pointer',
                        padding: '0.25rem 0.5rem'
                    }}
                >
                    Ask Copilot
                </button>
            </div>

            {activeTab === 'chat' ? (
                <div style={{ animation: 'fadeIn 0.3s ease-out', height: '100%' }}>
                    <ChatInterface phaseName={phase.id.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase())} />
                </div>
            ) : (
                <>
                    {isTyping || !analysis ? (
                        <div style={{ color: 'var(--text-muted)', fontSize: '0.875rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <div className="typing-indicator" style={{ display: 'flex', gap: '2px' }}>
                                <span style={{ animation: 'blink 1.4s infinite both', animationDelay: '0s' }}>.</span>
                                <span style={{ animation: 'blink 1.4s infinite both', animationDelay: '0.2s' }}>.</span>
                                <span style={{ animation: 'blink 1.4s infinite both', animationDelay: '0.4s' }}>.</span>
                            </div>
                            Analyzing phase context...
                        </div>
                    ) : (
                        <div style={{ animation: 'fadeIn 0.3s ease-out' }}>
                            <p style={{ fontSize: '0.9rem', marginBottom: '1rem', lineHeight: 1.6 }}>
                                {analysis.summary}
                            </p>

                            <div style={{ background: 'var(--bg-dark)', padding: '1rem', borderRadius: '0.5rem', marginBottom: '1rem' }}>
                                <h4 style={{ fontSize: '0.8rem', color: 'var(--accent-primary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.5rem' }}>
                                    Suggested Next Steps
                                </h4>
                                <ul style={{ margin: 0, paddingLeft: '1.2rem', fontSize: '0.85rem', color: 'var(--text-main)', display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
                                    {analysis.suggestedNextSteps.map((step, i) => (
                                        <li key={i}>{step}</li>
                                    ))}
                                </ul>
                            </div>

                            <div style={{ background: 'var(--bg-dark)', padding: '1rem', borderRadius: '0.5rem' }}>
                                <h4 style={{ fontSize: '0.8rem', color: 'var(--accent-warning)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.5rem' }}>
                                    Recommended Tool
                                </h4>
                                <div style={{ fontSize: '0.9rem', fontWeight: 500 }}>
                                    {analysis.toolRecommendation}
                                </div>
                                <button className="btn" style={{ marginTop: '0.75rem', fontSize: '0.75rem', padding: '0.25rem 0.5rem' }}>
                                    Generate Template
                                </button>
                            </div>
                        </div>
                    )}
                </>
            )}

            <style>{`
        @keyframes blink {
          0% { opacity: .2; }
          20% { opacity: 1; }
          100% { opacity: .2; }
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(5px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
        </div>
    );
}

import { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { simulateAgentResponse, type ChatMessage } from '../engine/chatSimulation';

interface ChatInterfaceProps {
    phaseName: string;
}

export default function ChatInterface({ phaseName }: ChatInterfaceProps) {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [inputValue, setInputValue] = useState('');
    const [isThinking, setIsThinking] = useState(false);
    const bottomRef = useRef<HTMLDivElement>(null);

    // Initial greeting
    useEffect(() => {
        setMessages([
            {
                id: '1',
                role: 'agent',
                content: `Let's discuss the **${phaseName}** phase. What do you need help with?`,
                timestamp: new Date()
            }
        ]);
    }, [phaseName]);

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages, isThinking]);

    const handleSend = async () => {
        if (!inputValue.trim()) return;

        const newUserMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            content: inputValue,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, newUserMsg]);
        setInputValue('');
        setIsThinking(true);

        const responseText = await simulateAgentResponse(newUserMsg.content, phaseName);

        const newAgentMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'agent',
            content: responseText,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, newAgentMsg]);
        setIsThinking(false);
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minHeight: '300px', maxHeight: '400px', borderRadius: '0.5rem', border: '1px solid var(--border-color)', overflow: 'hidden' }}>
            {/* Context Header */}
            <div style={{ padding: '0.75rem', background: 'var(--bg-dark)', borderBottom: '1px solid var(--border-color)', fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                Ask Copilot about tools, templates, or advice.
            </div>

            {/* Messages Area */}
            <div style={{ flex: 1, overflowY: 'auto', padding: '1rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {messages.map(msg => (
                    <div key={msg.id} style={{
                        alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                        maxWidth: '85%'
                    }}>
                        <div style={{
                            fontSize: '0.7rem',
                            color: 'var(--text-muted)',
                            marginBottom: '0.25rem',
                            textAlign: msg.role === 'user' ? 'right' : 'left'
                        }}>
                            {msg.role === 'user' ? 'You' : 'Copilot'} ΓÇó {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </div>
                        <div style={{
                            background: msg.role === 'user' ? 'var(--accent-primary)' : 'var(--bg-dark)',
                            color: msg.role === 'user' ? 'white' : 'var(--text-main)',
                            padding: '0.75rem 1rem',
                            borderRadius: '0.5rem',
                            borderBottomRightRadius: msg.role === 'user' ? '0' : '0.5rem',
                            borderBottomLeftRadius: msg.role === 'agent' ? '0' : '0.5rem',
                            fontSize: '0.9rem',
                            lineHeight: 1.5
                        }}>
                            {/* Use ReactMarkdown for Agent responses, simple string for User */}
                            {msg.role === 'agent' ? (
                                <ReactMarkdown components={{
                                    p: ({ node, ...props }) => <p style={{ margin: 0, padding: 0 }} {...props} />,
                                    ul: ({ node, ...props }) => <ul style={{ margin: '0.5rem 0', paddingLeft: '1.2rem' }} {...props} />
                                }}>
                                    {msg.content}
                                </ReactMarkdown>
                            ) : (
                                <span>{msg.content}</span>
                            )}
                        </div>
                    </div>
                ))}

                {isThinking && (
                    <div style={{ alignSelf: 'flex-start' }}>
                        <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>Copilot is typing...</div>
                        <div style={{ background: 'var(--bg-dark)', padding: '0.75rem 1rem', borderRadius: '0.5rem', borderBottomLeftRadius: 0, display: 'flex', gap: '4px' }}>
                            <span style={{ animation: 'blink 1.4s infinite both', animationDelay: '0s' }}>.</span>
                            <span style={{ animation: 'blink 1.4s infinite both', animationDelay: '0.2s' }}>.</span>
                            <span style={{ animation: 'blink 1.4s infinite both', animationDelay: '0.4s' }}>.</span>
                        </div>
                    </div>
                )}
                <div ref={bottomRef} />
            </div>

            {/* Input Area */}
            <div style={{ padding: '0.75rem', borderTop: '1px solid var(--border-color)', display: 'flex', gap: '0.5rem', background: 'var(--bg-dark)' }}>
                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="Ask a Lean question..."
                    style={{ flex: 1, padding: '0.5rem 0.75rem', borderRadius: '0.25rem', border: '1px solid var(--border-color)', background: 'var(--bg-card)', color: 'var(--text-main)', fontSize: '0.9rem' }}
                />
                <button
                    onClick={handleSend}
                    disabled={!inputValue.trim()}
                    style={{ background: 'var(--accent-primary)', color: 'white', border: 'none', borderRadius: '0.25rem', padding: '0 1rem', cursor: 'pointer', opacity: inputValue.trim() ? 1 : 0.5 }}
                >
                    Send
                </button>
            </div>
        </div>
    );
}

