import type { KaizenProject } from '../types';
import ProgressRing from './charts/ProgressRing';
import KPITrends from './charts/KPITrends';

interface DashboardProps {
    project: KaizenProject | null;
    onStartNew: () => void;
    onContinue: () => void;
}

export default function Dashboard({ project, onStartNew, onContinue }: DashboardProps) {
    return (
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
            <header style={{ marginBottom: '3rem', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                <img src="/gembaos-brand-logo.png" alt="GembaOS Logo" style={{ width: '100%', maxWidth: '400px', objectFit: 'contain', marginBottom: '1rem', filter: 'drop-shadow(0 4px 6px rgba(0,0,0,0.05))' }} />
                <p style={{ color: 'var(--text-muted)', fontSize: '1.2rem', fontWeight: 500 }}>
                    Your autonomous assistant for running highly effective Lean events.
                </p>
            </header>

            <div className="grid grid-cols-2">
                <div className="card interactive-row" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', textAlign: 'center', padding: '3rem 2rem' }} onClick={onStartNew}>
                    <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>≡ƒÜÇ</div>
                    <h3>Start New Project</h3>
                    <p style={{ color: 'var(--text-muted)', marginBottom: '2rem', fontSize: '0.9rem' }}>
                        Initialize a new Kaizen charter, define KPIs, and let the agent generate your roadmap automatically.
                    </p>
                    <button className="btn btn-primary" onClick={onStartNew} style={{ width: '100%', padding: '0.75rem' }}>
                        Create Charter
                    </button>
                </div>

                <div className="card" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', textAlign: 'center', padding: '3rem 2rem' }}>
                    <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>≡ƒôè</div>
                    <h3>Active Project</h3>
                    {project ? (
                        <>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem', marginBottom: '1.5rem', textAlign: 'left', width: '100%' }}>
                                <ProgressRing
                                    radius={40}
                                    stroke={6}
                                    progress={Math.round((project.phases.filter(p => p.status === 'completed').length / project.phases.length) * 100)}
                                    color="var(--accent-primary)"
                                />
                                <div>
                                    <h4 style={{ color: 'var(--accent-primary)', marginBottom: '0.25rem', fontSize: '1.2rem' }}>{project.name}</h4>
                                    <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>{project.duration} ΓÇó {project.intensity}</p>
                                    <p style={{ fontSize: '0.75rem', color: 'var(--text-main)', marginTop: '0.25rem' }}>
                                        {project.phases.filter(p => p.status === 'completed').length} of {project.phases.length} phases completed
                                    </p>
                                </div>
                            </div>
                            <button className="btn" onClick={onContinue} style={{ width: '100%', padding: '0.75rem' }}>
                                Resume Execution
                            </button>

                            {project.kpis.length > 0 && (
                                <div style={{ marginTop: '1.5rem', width: '100%', borderTop: '1px solid var(--border-color)', paddingTop: '1.5rem', textAlign: 'left' }}>
                                    <h5 style={{ color: 'var(--text-muted)', marginBottom: '1rem', fontSize: '0.85rem', textTransform: 'uppercase' }}>
                                        {project.kpis[0].name} Tracker
                                    </h5>
                                    <div style={{ background: 'var(--bg-dark)', borderRadius: '0.5rem', padding: '1rem', display: 'flex', justifyContent: 'center' }}>
                                        <KPITrends
                                            // Mock data generator for the visual based on the baseline/target to represent "trends"
                                            data={
                                                project.phases.filter(p => p.status === 'completed').map((p, i) => {
                                                    const base = parseFloat(project.kpis[0].baseline) || 0;
                                                    const targ = parseFloat(project.kpis[0].target) || 100;
                                                    const progressRatio = (i + 1) / project.phases.length;
                                                    const simulatedValue = base + ((targ - base) * progressRatio * (0.8 + Math.random() * 0.4)); // Some faux variation
                                                    return { day: p.day, value: Math.round(simulatedValue) };
                                                })
                                            }
                                            baseline={parseFloat(project.kpis[0].baseline) || 0}
                                            target={parseFloat(project.kpis[0].target) || 100}
                                            width={340}
                                            height={160}
                                        />
                                    </div>
                                </div>
                            )}
                        </>
                    ) : (
                        <>
                            <p style={{ color: 'var(--text-muted)', marginBottom: '2rem', fontSize: '0.9rem' }}>
                                No active project found in local storage. Start a new one to begin.
                            </p>
                            <button className="btn" disabled style={{ width: '100%', padding: '0.75rem', opacity: 0.5 }}>
                                Resume Execution
                            </button>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import type { KaizenPhase, KaizenProject, PhaseEvidence } from '../types';
import AgentPanel from './AgentPanel';

interface RoadmapViewProps {
    project: KaizenProject;
    setProject: (p: KaizenProject) => void;
}

export default function RoadmapView({ project, setProject }: RoadmapViewProps) {
    const [activePhaseIndex, setActivePhaseIndex] = useState(0);

    const activePhase = project.phases[activePhaseIndex];

    const updatePhaseStatus = (status: KaizenPhase['status']) => {
        const updated = { ...project };
        updated.phases[activePhaseIndex].status = status;
        setProject(updated);
    };

    const addEvidence = (type: PhaseEvidence['type'], content: string) => {
        const ev: PhaseEvidence = {
            id: Date.now().toString(),
            type,
            content,
            timestamp: new Date().toLocaleTimeString()
        };
        const updated = { ...project };
        updated.phases[activePhaseIndex].evidence.push(ev);
        setProject(updated);
    };

    return (
        <div style={{ display: 'flex', gap: '2rem', height: '100%', flexWrap: 'wrap' }}>
            {/* Left side: Roadmap timeline */}
            <div style={{ flex: '1 1 320px', minWidth: 'min(100%, 400px)' }}>
                <header style={{ marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <img src="/gembaos-app-icon.png" alt="GembaOS Icon" style={{ width: '48px', height: '48px', borderRadius: '0.5rem', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' }} />
                    <div>
                        <h2 style={{ margin: 0, color: 'var(--text-main)', fontSize: '1.75rem' }}>Execution Roadmap</h2>
                        <p style={{ margin: 0, color: 'var(--text-muted)' }}>Select a phase to view details and upload evidence.</p>
                    </div>
                </header>

                <div className="timeline">
                    {project.phases.map((phase, idx) => (
                        <div
                            key={phase.id}
                            className="timeline-item"
                            style={{
                                cursor: 'pointer',
                                opacity: activePhaseIndex === idx ? 1 : 0.6,
                                transform: activePhaseIndex === idx ? 'translateX(0.5rem)' : 'none',
                                transition: 'all 0.2s ease'
                            }}
                            onClick={() => setActivePhaseIndex(idx)}
                        >
                            <div
                                className="card"
                                style={{
                                    borderColor: activePhaseIndex === idx ? 'var(--accent-primary)' : 'var(--border-color)',
                                    backgroundColor: activePhaseIndex === idx ? 'var(--bg-panel-hover)' : 'var(--bg-panel)'
                                }}
                            >
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
                                    <span className="pill" style={{
                                        backgroundColor: phase.status === 'completed' ? 'var(--accent-success)' : 'rgba(59, 130, 246, 0.1)',
                                        color: phase.status === 'completed' ? '#fff' : 'var(--accent-primary)',
                                        borderColor: 'transparent'
                                    }}>
                                        {phase.status.toUpperCase()}
                                    </span>
                                    <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Day {phase.day}</span>
                                </div>
                                <h4 style={{ marginBottom: '0.25rem' }}>{phase.title}</h4>
                                <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>{phase.description}</p>

                                {phase.evidence.length > 0 && (
                                    <div style={{ marginTop: '0.5rem', fontSize: '0.75rem', color: 'var(--accent-primary)' }}>
                                        ≡ƒôÄ {phase.evidence.length} pieces of evidence attached
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Right side: Phase Execution & Agent */}
            <div style={{ flex: '1 1 320px', display: 'flex', flexDirection: 'column', gap: '1.5rem', maxWidth: '100%' }}>
                {/* Active Phase Dashboard */}
                <div className="card">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <h3>Phase Execution</h3>
                        <select
                            value={activePhase.status}
                            onChange={e => updatePhaseStatus(e.target.value as any)}
                            className="input-field"
                            style={{ width: 'auto', padding: '0.25rem 0.5rem' }}
                        >
                            <option value="pending">Pending</option>
                            <option value="in-progress">In Progress</option>
                            <option value="completed">Completed</option>
                        </select>
                    </div>

                    <div style={{ marginBottom: '1.5rem' }}>
                        <h4 style={{ color: 'var(--accent-primary)' }}>{activePhase.title}</h4>
                        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap', marginTop: '0.5rem' }}>
                            {activePhase.suggestedTools.map(t => (
                                <span key={t} className="pill" style={{ background: '#374151', color: '#e5e7eb', borderColor: '#4b5563' }}>
                                    ≡ƒ¢á {t}
                                </span>
                            ))}
                        </div>
                    </div>

                    <div style={{ borderTop: '1px solid var(--border-color)', paddingTop: '1rem' }}>
                        <h4 style={{ marginBottom: '1rem', fontSize: '1rem' }}>Evidence & Data Log</h4>
                        <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
                            <button className="btn" onClick={() => {
                                const note = prompt('Enter text note or URL for evidence:');
                                if (note) addEvidence('note', note);
                            }}>+ Add Note</button>
                            <button className="btn" onClick={() => {
                                const url = prompt('Enter Image URL (or photo path):');
                                if (url) addEvidence('photo', url);
                            }}>+ Upload Photo</button>
                        </div>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            {activePhase.evidence.map(ev => (
                                <div key={ev.id} style={{ padding: '0.75rem', background: 'var(--bg-dark)', borderRadius: '0.5rem', fontSize: '0.875rem' }}>
                                    <strong>{ev.type.toUpperCase()}</strong> ({ev.timestamp}): {ev.content}
                                </div>
                            ))}
                            {activePhase.evidence.length === 0 && (
                                <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem', fontStyle: 'italic' }}>No evidence logged for this phase yet.</p>
                            )}
                        </div>
                    </div>
                </div>

                {/* AI Agent Panel */}
                <div className="card glass-panel" style={{ position: 'sticky', top: '2rem' }}>
                    <AgentPanel phase={activePhase} />
                </div>
            </div>
        </div>
    );
}

