import { useState, useRef, useEffect } from 'react';

export interface TimeStudyElement {
    id: string;
    name: string;
    cycles: number[]; // Array of recorded times in seconds
}

export default function TimeStudy() {
    const [elements, setElements] = useState<TimeStudyElement[]>([]);
    const [newElementName, setNewElementName] = useState('');

    // Stopwatch State
    const [isRunning, setIsRunning] = useState(false);
    const [elapsedTime, setElapsedTime] = useState(0);
    const timerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number | null>(null);

    // Active recording state
    const [activeElementId, setActiveElementId] = useState<string | null>(null);

    // Load saved data
    useEffect(() => {
        const saved = localStorage.getItem('kaizen_timestudy_data');
        if (saved) {
            try {
                setElements(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load time study data", e);
            }
        }
    }, []);

    // Save data whenever elements change
    useEffect(() => {
        localStorage.setItem('kaizen_timestudy_data', JSON.stringify(elements));
    }, [elements]);

    // Stopwatch Logic
    const startTimer = () => {
        if (!isRunning) {
            startTimeRef.current = Date.now() - (elapsedTime * 1000);
            timerRef.current = window.setInterval(() => {
                if (startTimeRef.current) {
                    setElapsedTime((Date.now() - startTimeRef.current) / 1000);
                }
            }, 100); // Update every 100ms for smooth deciseconds
            setIsRunning(true);
        }
    };

    const stopTimer = () => {
        if (isRunning && timerRef.current) {
            clearInterval(timerRef.current);
            setIsRunning(false);
        }
    };

    const resetTimer = () => {
        stopTimer();
        setElapsedTime(0);
        startTimeRef.current = null;
    };

    // Cleanup interval on unmount
    useEffect(() => {
        return () => {
            if (timerRef.current) clearInterval(timerRef.current);
        };
    }, []);

    // Element Management
    const handleAddElement = (e: React.FormEvent) => {
        e.preventDefault();
        if (!newElementName.trim()) return;

        setElements([...elements, {
            id: crypto.randomUUID(),
            name: newElementName.trim(),
            cycles: []
        }]);
        setNewElementName('');
    };

    const handleDeleteElement = (id: string) => {
        setElements(elements.filter(e => e.id !== id));
        if (activeElementId === id) setActiveElementId(null);
    };

    const handleRecordCycle = (elementId: string) => {
        if (elapsedTime === 0) return;

        setElements(elements.map(el => {
            if (el.id === elementId) {
                return { ...el, cycles: [...el.cycles, Number(elapsedTime.toFixed(1))] };
            }
            return el;
        }));

        // Reset timer automatically for continuous study flow
        resetTimer();
        startTimer();
    };

    const handleDeleteCycle = (elementId: string, cycleIndex: number) => {
        setElements(elements.map(el => {
            if (el.id === elementId) {
                const newCycles = [...el.cycles];
                newCycles.splice(cycleIndex, 1);
                return { ...el, cycles: newCycles };
            }
            return el;
        }));
    };

    // Calculations
    const getCalculations = (cycles: number[]) => {
        if (cycles.length === 0) return { avg: 0, min: 0, max: 0, count: 0 };
        const sum = cycles.reduce((a, b) => a + b, 0);
        const min = Math.min(...cycles);
        const max = Math.max(...cycles);
        return {
            avg: Number((sum / cycles.length).toFixed(1)),
            min,
            max,
            count: cycles.length
        };
    };

    const formatDisplayTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = (seconds % 60).toFixed(1);
        return mins > 0 ? `${mins}m ${secs}s` : `${secs}s`;
    };

    const exportCSV = () => {
        if (elements.length === 0) return;

        let csvContent = 'Process Element,Cycle 1,Cycle 2,Cycle 3,Cycle 4,Cycle 5,Cycle 6,Cycle 7,Cycle 8,Cycle 9,Cycle 10,Average,Min,Max\n';

        // Find max cycles to pad the headers if needed (up to 10 for standard, or dynamic)
        const maxCycles = Math.max(...elements.map(e => e.cycles.length), 10);

        const dynamicHeaders = ['Process Element'];
        for (let i = 1; i <= maxCycles; i++) dynamicHeaders.push(`Cycle ${i}`);
        dynamicHeaders.push('Average', 'Min', 'Max');

        csvContent = dynamicHeaders.join(',') + '\n';

        elements.forEach(el => {
            const calc = getCalculations(el.cycles);
            const row = [`"${el.name}"`];

            // Pad cycles
            for (let i = 0; i < maxCycles; i++) {
                row.push(el.cycles[i] !== undefined ? String(el.cycles[i]) : '');
            }

            row.push(String(calc.avg), String(calc.min), String(calc.max));
            csvContent += row.join(',') + '\n';
        });

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', 'Time_Study_Export.csv');
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div style={{ maxWidth: '1000px', margin: '0 auto', paddingBottom: '4rem' }}>
            <header style={{ marginBottom: '2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '1rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <img src="/gembaos-app-icon.png" alt="GembaOS Icon" style={{ width: '48px', height: '48px', borderRadius: '0.5rem', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' }} />
                    <div>
                        <h2 style={{ fontSize: '2rem', margin: 0, color: 'var(--text-main)', fontWeight: 700 }}>
                            Time Study Tool
                        </h2>
                        <p style={{ color: 'var(--text-muted)', margin: 0 }}>Perform live cycle time observations, record discrete process elements, and calculate averages.</p>
                    </div>
                </div>

                {/* Global Stopwatch Widget */}
                <div style={{
                    background: 'var(--bg-panel)',
                    padding: '1rem 2rem',
                    borderRadius: '0.5rem',
                    border: '2px solid var(--accent-primary)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    minWidth: '250px'
                }}>
                    <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '0.5rem' }}>
                        Live Stopwatch
                    </div>
                    <div style={{ fontSize: '3rem', fontWeight: 'bold', fontFamily: 'monospace', color: 'var(--text-main)', lineHeight: '1' }}>
                        {formatDisplayTime(elapsedTime)}
                    </div>

                    <div style={{ display: 'flex', gap: '0.5rem', marginTop: '1rem', width: '100%' }}>
                        {!isRunning ? (
                            <button onClick={startTimer} className="btn btn-primary" style={{ flex: 1, padding: '0.5rem' }}>Start</button>
                        ) : (
                            <button onClick={stopTimer} className="btn" style={{ flex: 1, padding: '0.5rem', background: 'var(--accent-danger)', color: 'white', border: 'none' }}>Stop</button>
                        )}
                        <button onClick={resetTimer} className="btn" style={{ flex: 1, padding: '0.5rem' }}>Reset</button>
                    </div>
                </div>
            </header>

            {/* Input Form */}
            <div className="card" style={{ marginBottom: '2rem' }}>
                <form onSubmit={handleAddElement} style={{ display: 'flex', gap: '1rem', alignItems: 'flex-end' }}>
                    <div className="input-group" style={{ marginBottom: 0, flex: 1 }}>
                        <label className="input-label">Process Element Name</label>
                        <input
                            type="text"
                            className="input-field"
                            value={newElementName}
                            onChange={e => setNewElementName(e.target.value)}
                            required
                            placeholder="e.g. Walk to parts bin"
                        />
                    </div>
                    <button type="submit" className="btn btn-primary" style={{ padding: '0.6rem 1.5rem', height: '38px' }}>+ Add Element</button>
                    {elements.length > 0 && (
                        <button type="button" onClick={exportCSV} className="btn" style={{ padding: '0.6rem 1rem', height: '38px', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <span>≡ƒôÑ</span> Export CSV
                        </button>
                    )}
                </form>
            </div>

            {/* Elements List */}
            {elements.length > 0 ? (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    {elements.map((el) => {
                        const calc = getCalculations(el.cycles);
                        const isRecordingHere = isRunning && activeElementId === el.id;

                        return (
                            <div key={el.id} className="card" onClick={() => setActiveElementId(el.id)} style={{ borderLeft: isRecordingHere ? '4px solid var(--accent-success)' : '4px solid transparent', cursor: 'pointer', transition: 'all 0.2s', padding: '1rem 1.5rem' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                                    <div>
                                        <h3 style={{ margin: '0 0 0.5rem 0', fontSize: '1.2rem', color: isRecordingHere ? 'var(--accent-success)' : 'var(--text-main)' }}>{el.name}</h3>
                                        <div style={{ display: 'flex', gap: '1rem', fontSize: '0.85rem' }}>
                                            <span style={{ color: 'var(--text-muted)' }}>Cycles: <strong style={{ color: 'var(--text-main)' }}>{calc.count}</strong></span>
                                            <span style={{ color: 'var(--text-muted)' }}>Avg: <strong style={{ color: 'var(--accent-primary)' }}>{calc.avg > 0 ? formatDisplayTime(calc.avg) : '--'}</strong></span>
                                            <span style={{ color: 'var(--text-muted)' }}>Range: <strong>{calc.min > 0 ? formatDisplayTime(calc.min) : '--'} - {calc.max > 0 ? formatDisplayTime(calc.max) : '--'}</strong></span>
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); handleRecordCycle(el.id); }}
                                            disabled={!isRunning && elapsedTime === 0}
                                            className="btn btn-primary"
                                            style={{ padding: '0.4rem 1rem', fontSize: '0.85rem' }}
                                        >
                                            ΓÅ▒ Record Time
                                        </button>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); handleDeleteElement(el.id); }}
                                            style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '1.2rem', padding: '0 0.5rem' }}
                                        >
                                            ├ù
                                        </button>
                                    </div>
                                </div>

                                {/* Recorded Cycles List */}
                                {el.cycles.length > 0 && (
                                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid var(--border-color)' }}>
                                        {el.cycles.map((time, idx) => {
                                            const isOutlier = time > calc.avg * 1.5 || (time < calc.avg * 0.5 && calc.avg > 0);
                                            return (
                                                <div key={idx} style={{
                                                    background: isOutlier ? 'rgba(239, 68, 68, 0.1)' : 'var(--bg-dark)',
                                                    border: `1px solid ${isOutlier ? 'var(--accent-danger)' : 'var(--border-color)'}`,
                                                    padding: '0.25rem 0.5rem',
                                                    borderRadius: '0.25rem',
                                                    fontSize: '0.8rem',
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    gap: '0.5rem'
                                                }}>
                                                    <span style={{ color: 'var(--text-muted)' }}>#{idx + 1}</span>
                                                    <span style={{ fontWeight: 'bold', color: isOutlier ? 'var(--accent-danger)' : 'var(--text-main)' }}>{time.toFixed(1)}s</span>
                                                    <button
                                                        onClick={(e) => { e.stopPropagation(); handleDeleteCycle(el.id, idx); }}
                                                        style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', padding: 0, marginLeft: '0.25rem', fontSize: '1rem', lineHeight: 1 }}
                                                    >
                                                        ├ù
                                                    </button>
                                                </div>
                                            );
                                        })}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            ) : (
                <div style={{ textAlign: 'center', padding: '4rem 2rem', color: 'var(--text-muted)', background: 'var(--bg-panel)', borderRadius: '0.5rem', border: '1px dashed var(--border-color)' }}>
                    <h3 style={{ marginTop: 0 }}>No Process Elements</h3>
                    <p>Add a process element above, start the stopwatch, and click "Record Time" to log cycle times.</p>
                </div>
            )}

            <div style={{ marginTop: '2rem', padding: '1rem', background: 'rgba(59, 130, 246, 0.1)', borderLeft: '4px solid #3b82f6', borderRadius: '0.25rem', fontSize: '0.85rem' }}>
                <strong style={{ color: '#3b82f6' }}>Tip:</strong> Clicking "Record Time" will automatically log the elapsed time to that element and reset/restart the stopwatch so you can immediately begin timing the next continuous element. Outliers (┬▒50% of the average) are highlighted in red.
            </div>
        </div>
    );
}

